<?php foreach ($activities as $activity): ?><tr class="<?= !empty($activity['deleted_at']) ? 'deleted-row' : '' ?>"><td><?= e($activity['activity_date']) ?></td><td><?= e($activity['group_name']) ?></td><td><?= e($activity['type_name']) ?></td><td><?= (int)$activity['present_count'] ?> / <?= (int)$activity['total_count'] ?></td><td><?= e($activity['creator_name']) ?></td><td><?= e((string)$activity['notes']) ?: '—' ?></td><td class="table-actions"><a href="activity_view.php?id=<?= (int)$activity['id'] ?>">צפייה</a><?php if (empty($activity['deleted_at'])): ?> | <a href="activity_form.php?id=<?= (int)$activity['id'] ?>">עריכה</a> | <form method="post" action="delete_activity.php" class="inline-form"><?= csrfField() ?><input type="hidden" name="id" value="<?= (int)$activity['id'] ?>"><button class="link-button confirm-action" type="submit">מחיקה</button></form><?php else: ?> | <form method="post" action="restore_activity.php" class="inline-form"><?= csrfField() ?><input type="hidden" name="id" value="<?= (int)$activity['id'] ?>"><button class="link-button" type="submit">שחזור</button></form><?php endif; ?></td></tr><?php endforeach; ?>
<?php if (!$activities): ?><tr><td colspan="7" class="centered muted">לא נמצאו פעילויות.</td></tr><?php endif; ?>
